from dataclasses import dataclass
from enum import IntEnum

class ImpactScore(IntEnum):
    COSMETIC         = 1  # no functional effect; affects code readability or developer experience only
    FRICTION         = 2  # causes minor friction but does not block task completion
    LATENT_RISK      = 3  # does not cause problems now but will under foreseeable conditions
    QUALITY_DEGRADED = 4  # measurably reduces response quality or reliability
    USER_FACING_FAIL = 5  # directly causes user-facing failures or errors

class UrgencyScore(IntEnum):
    STABLE_DECLINING  = 1  # cost to fix is not increasing over time
    COMPOUNDING_QTR   = 2  # cost increases each quarter (model drift, stale patches)
    COMPOUNDING_DAILY = 3  # cost increases with every interaction or each day

class BreadthScore(IntEnum):
    SINGLE            = 1  # affects one user, one configuration, or one edge case
    SUBSET            = 2  # affects a segment of users (e.g., users with long prompts)
    ALL_USERS         = 3  # affects the majority of or all users of the integration

@dataclass
class DebtPriorityScore:
    impact: ImpactScore
    urgency: UrgencyScore
    breadth: BreadthScore

    def score(self) -> int:
        return int(self.impact) * int(self.urgency) * int(self.breadth)

    def tier(self) -> str:
        s = self.score()
        if s >= 30:
            return "P1"
        if s >= 15:
            return "P2"
        if s >= 5:
            return "P3"
        return "P4"

    def score_breakdown(self) -> str:
        return (
            f"Score: {self.score()} = "
            f"Impact({int(self.impact)}) × "
            f"Urgency({int(self.urgency)}) × "
            f"Breadth({int(self.breadth)}) → {self.tier()}"
        )

from dataclasses import dataclass, field
from datetime import date

@dataclass
class ScoredDebtRecord:
    """
    Extends TechDebtRecord with a computed priority score and optional override.
    """
    debt_id: str
    title: str
    category: "DebtCategory"
    description: str
    date_identified: date
    owner: str

    impact: ImpactScore
    urgency: UrgencyScore
    breadth: BreadthScore

    # Override (optional)
    override_tier: str | None = None          # "P1" | "P2" | "P3" | "P4" or None
    override_reason: str = ""                 # required if override_tier is set
    override_approved_by: str = ""

    def computed_tier(self) -> str:
        return DebtPriorityScore(self.impact, self.urgency, self.breadth).tier()

    def effective_tier(self) -> str:
        return self.override_tier if self.override_tier is not None else self.computed_tier()

    def is_overridden(self) -> bool:
        return self.override_tier is not None

    def override_valid(self) -> bool:
        if not self.is_overridden():
            return True
        return bool(self.override_reason and self.override_approved_by)

    def full_record_line(self) -> str:
        score = DebtPriorityScore(self.impact, self.urgency, self.breadth)
        base = score.score_breakdown()
        if self.is_overridden():
            return f"{self.debt_id} [{self.effective_tier()}]: {self.title} | {base} → override to {self.override_tier} ({self.override_reason})"
        return f"{self.debt_id} [{self.effective_tier()}]: {self.title} | {base}"

from dataclasses import dataclass, field
from datetime import date

@dataclass
class ScoreCalibrationEvent:
    debt_id: str
    calibration_date: date
    previous_score: "DebtPriorityScore"
    new_score: "DebtPriorityScore"
    change_reason: str   # what changed in context that warrants rescoring

    def tier_changed(self) -> bool:
        return self.previous_score.tier() != self.new_score.tier()

    def escalated(self) -> bool:
        """
        True if the new tier is higher priority than the old tier
        (i.e., debt became more urgent).
        """
        tier_order = {"P1": 1, "P2": 2, "P3": 3, "P4": 4}
        return tier_order[self.new_score.tier()] < tier_order[self.previous_score.tier()]

    def calibration_note(self) -> str:
        prev = self.previous_score.score_breakdown()
        new = self.new_score.score_breakdown()
        direction = "ESCALATED" if self.escalated() else "DE-ESCALATED" if self.tier_changed() else "UNCHANGED TIER"
        return f"{self.debt_id} ({self.calibration_date}): {direction}\n  Before: {prev}\n  After:  {new}\n  Reason: {self.change_reason}"

@dataclass
class DebtScoreAuditLog:
    records: list[ScoreCalibrationEvent] = field(default_factory=list)

    def add(self, event: ScoreCalibrationEvent) -> None:
        self.records.append(event)

    def escalations_this_quarter(self, quarter_start: date, today: date) -> list[ScoreCalibrationEvent]:
        return [
            e for e in self.records
            if e.calibration_date >= quarter_start
            and e.calibration_date <= today
            and e.escalated()
        ]

    def patterns(self, quarter_start: date, today: date) -> str:
        escalations = self.escalations_this_quarter(quarter_start, today)
        if not escalations:
            return "No score escalations this quarter — register is stable"
        reasons = [e.change_reason for e in escalations]
        return f"{len(escalations)} escalations this quarter: " + "; ".join(reasons)

from dataclasses import dataclass, field

@dataclass
class PromptInstruction:
    instruction_id: str
    text: str
    source_patch_id: str | None  # which PromptPatch introduced this instruction
    impact: ImpactScore
    urgency: UrgencyScore
    breadth: BreadthScore
    still_needed: bool = True    # False if the instruction is a no-op or obsolete

    def priority(self) -> str:
        return DebtPriorityScore(self.impact, self.urgency, self.breadth).tier()

    def is_candidate_for_removal(self) -> bool:
        return not self.still_needed

@dataclass
class PromptRefactorPlan:
    prompt_version: str
    instructions: list[PromptInstruction] = field(default_factory=list)

    def removals(self) -> list[PromptInstruction]:
        return [i for i in self.instructions if i.is_candidate_for_removal()]

    def by_priority(self) -> dict[str, list[PromptInstruction]]:
        result: dict[str, list[PromptInstruction]] = {"P1": [], "P2": [], "P3": [], "P4": []}
        for inst in self.instructions:
            if inst.still_needed:
                result[inst.priority()].append(inst)
        return result

    def refactor_order(self) -> list[PromptInstruction]:
        """
        Returns instructions in priority order for a structured refactor session.
        P1 instructions are rewritten first; P4 are addressed last or deferred.
        """
        by_prio = self.by_priority()
        return by_prio["P1"] + by_prio["P2"] + by_prio["P3"] + by_prio["P4"]

    def refactor_summary(self) -> str:
        by_prio = self.by_priority()
        removals = self.removals()
        return (
            f"Prompt refactor plan: {self.prompt_version}\n"
            f"  Remove (obsolete): {len(removals)} instructions\n"
            f"  Rewrite P1: {len(by_prio['P1'])} | P2: {len(by_prio['P2'])} | "
            f"P3: {len(by_prio['P3'])} | P4: {len(by_prio['P4'])}"
        )
